import os
from dotenv import load_dotenv
from langchain_community.document_loaders import TextLoader
from langchain_text_splitters import RecursiveCharacterTextSplitter
from langchain_openai import OpenAIEmbeddings
from langchain_chroma import Chroma

# Load environment variables from .env file
load_dotenv()

# --- Configuration ---
# Set your OpenAI API key as an environment variable or in .env
# os.environ["OPENAI_API_KEY"] = "YOUR_OPENAI_API_KEY"

# Path to your company documents directory or a single file
DOCUMENT_PATH = "company_documents.txt" # Create this file with some dummy text
CHROMA_DB_PATH = "./chroma_db"
CHUNK_SIZE = 1000
CHUNK_OVERLAP = 200
TOP_K_RETRIEVAL = 4

# --- 1. Document Loading and Splitting ---
def load_and_split_documents(document_path: str):
    """Loads documents from a file and splits them into chunks."""
    if not os.path.exists(document_path):
        print(f"Error: Document file not found at {document_path}")
        print("Please create a 'company_documents.txt' file with your content.")
        exit()

    print(f"Loading documents from {document_path}...")
    loader = TextLoader(document_path)
    documents = loader.load()

    text_splitter = RecursiveCharacterTextSplitter(
        chunk_size=CHUNK_SIZE,
        chunk_overlap=CHUNK_OVERLAP,
        length_function=len,
        add_start_index=True,
    )
    splits = text_splitter.split_documents(documents)
    print(f"Split {len(documents)} document(s) into {len(splits)} chunks.")
    return splits

# --- 2. Embedding Generation and Vector Database Creation ---
def create_vector_database(splits, db_path: str):
    """Creates or loads a Chroma vector database from document splits."""
    print("Initializing OpenAI Embeddings...")
    if not os.getenv("OPENAI_API_KEY"):
        raise ValueError("OPENAI_API_KEY environment variable not set. Please set it to use OpenAIEmbeddings.")

    embeddings = OpenAIEmbeddings()

    print("Creating/Loading Chroma DB...")
    # Use Chroma.from_documents to create and persist, or load if it exists
    # If the directory exists, Chroma.from_documents will typically add to it.
    # To ensure a fresh DB, you might delete the directory first.
    if os.path.exists(db_path) and os.listdir(db_path):
        print(f"Loading existing Chroma DB from {db_path}...")
        vectorstore = Chroma(persist_directory=db_path, embedding_function=embeddings)
        # You might want to update the DB with new documents if they change
        # For simplicity, this example just loads or creates.
    else:
        print(f"Creating new Chroma DB at {db_path} with {len(splits)} chunks...")
        vectorstore = Chroma.from_documents(
            documents=splits,
            embedding=embeddings,
            persist_directory=db_path
        )
        vectorstore.persist()
        print("Chroma DB created and persisted.")

    return vectorstore

# --- 3. RAG System ---
def retrieve_and_generate(query: str, vectorstore, k: int = TOP_K_RETRIEVAL):
    """
    Retrieves relevant documents and generates a response using a simulated LLM.
    In a real system, this would integrate with an actual LLM API.
    """
    print(f"\n--- Processing Query: '{query}' ---")

    # 3.1 Retrieve relevant documents
    print(f"Retrieving top {k} relevant documents...")
    retrieved_docs = vectorstore.similarity_search(query, k=k)

    print(f"Found {len(retrieved_docs)} relevant documents:")
    context_text = []
    for i, doc in enumerate(retrieved_docs):
        print(f"--- Document {i+1} ---")
        print(f"Source: {doc.metadata.get('source', 'N/A')}, Start Index: {doc.metadata.get('start_index', 'N/A')}")
        print(doc.page_content[:200] + "...") # Print first 200 chars
        context_text.append(doc.page_content)

    # 3.2 Format context for LLM prompt
    formatted_context = "\n\n".join(context_text)

    # 3.3 Construct the LLM prompt
    # In a real system, you would pass this prompt to an actual LLM.
    llm_prompt = f"""
Given the following context from our company's internal knowledge base, please answer the user's query.
Ensure your answer is comprehensive and directly addresses the question based *only* on the provided context.
If the answer cannot be found in the context, state that you don't have enough information.

--- Context ---
{formatted_context}

--- User Query ---
{query}

--- Response ---
"""
    print("\n--- LLM Prompt (partial display) ---")
    print(llm_prompt[:500] + "...\n" + llm_prompt[-200:])

    # 3.4 Simulate LLM Response
    # In a real application, you would make an API call here, e.g.:
    # from langchain_openai import ChatOpenAI
    # llm = ChatOpenAI(model_name="gpt-4o", temperature=0.0)
    # response = llm.invoke(llm_prompt)
    # return response.content

    # For demonstration, we'll just return a placeholder.
    # A more sophisticated mock could try to extract answers from context.
    mock_response = (
        "Thank you for your query. Based on the provided context from our internal knowledge base, "
        "here is what I found:\n\n"
        "SIMULATED LLM ANSWER: [This would be the actual answer generated by an LLM based on the context and query.]\n"
        "For example, if your query was about 'vacation policy' and the context had details, "
        "the LLM would summarize those details here. "
        "Please note: This is a placeholder. Integrate with an actual LLM (e.g., OpenAI, Anthropic, Hugging Face) "
        "to get real responses."
    )
    return mock_response

